async (params, browser) => {
  // Open deals page
  await browser.open(`https://www.walmart.com/shop/deals/${params.category}`)

  // Wait for deals to load
  await browser.waitForSelector('[data-item-id], [class*=\'product-card\'], [class*=\'deal-card\'], [class*=\'tile\']', 15000)

  // Let page render
  await browser.wait(2000)

  // Scroll to load more deals
  await browser.scroll({ direction: 'down', amount: 1200 })

  await browser.wait(1500)

  // Scroll further
  await browser.scroll({ direction: 'down', amount: 1200 })

  await browser.wait(1500)

  // Extract deals
  const deals_data = await browser.evaluate(`const deals = []; const items = document.querySelectorAll('[data-item-id], [class*="product-card"], [class*="deal-card"], [class*="tile-content"]'); for (let i = 0; i < Math.min(items.length, 20); i++) { const el = items[i]; const titleEl = el.querySelector('[class*="title"], [data-automation-id="product-title"], a span, h3'); const currentPriceEl = el.querySelector('[class*="price-main"], [class*="current-price"], [class*="sale-price"]'); const originalPriceEl = el.querySelector('[class*="was-price"], [class*="list-price"], [class*="strikethrough"], s, del'); const discountEl = el.querySelector('[class*="savings"], [class*="discount"], [class*="badge"]'); const linkEl = el.querySelector('a[href*="/ip/"], a'); const imgEl = el.querySelector('img'); const ratingEl = el.querySelector('[class*="rating"], [class*="stars"]'); deals.push({ title: titleEl ? titleEl.textContent.trim().substring(0, 200) : '', current_price: currentPriceEl ? currentPriceEl.textContent.trim() : '', original_price: originalPriceEl ? originalPriceEl.textContent.trim() : '', discount: discountEl ? discountEl.textContent.trim() : '', rating: ratingEl ? ratingEl.textContent.trim() : '', url: linkEl ? linkEl.href : '', image: imgEl ? imgEl.getAttribute('src') : '' }); } return { category: '' + params.category + '', deal_count: deals.length, deals: deals, url: window.location.href }`)

  return deals_data
}
